# test_search_client.py -- mock httpx transport with respx
# pip install pytest pytest-anyio respx

import pytest
import respx
import httpx
from search_client import SearchClient, SearchResponse

BASE = "https://api.example.com"
KEY = "test-key"


@pytest.mark.anyio
@respx.mock
async def test_search_returns_results():
    respx.get(f"{BASE}/search").mock(
        return_value=httpx.Response(
            200,
            json={
                "results": [
                    {"id": "1", "title": "Hello", "url": "https://ex.com", "score": 0.9}
                ],
                "total": 1,
                "next_cursor": None,
            },
        )
    )
    async with SearchClient(BASE, KEY) as client:
        resp = await client.search("hello")
    assert isinstance(resp, SearchResponse)
    assert resp.results[0].id == "1"
    assert resp.total == 1


@pytest.mark.anyio
@respx.mock
async def test_search_raises_on_bad_schema():
    respx.get(f"{BASE}/search").mock(
        return_value=httpx.Response(200, json={"totally": "wrong"})
    )
    with pytest.raises(ValueError, match="Unexpected response schema"):
        async with SearchClient(BASE, KEY) as client:
            await client.search("hello")


@pytest.mark.anyio
@respx.mock
async def test_search_raises_on_http_error():
    respx.get(f"{BASE}/search").mock(
        return_value=httpx.Response(429, json={"error": "rate limited"})
    )
    with pytest.raises(httpx.HTTPStatusError):
        async with SearchClient(BASE, KEY) as client:
            await client.search("hello")
